declare(strict_types=1);require __DIR__.'/bootstrap.php';use App\Domain\ControlEscaneres\{ScannerCode,BatteryPercentage,ConservationIndex,ScannerStatus,MovementStatus,InspectionType,IncidentSeverity,IncidentStatus,ScannerFolio};use App\DTO\ControlEscaneres\ScannerFilterData;use App\Validators\ControlEscaneres\AuditPayloadSanitizer;
test('SC válido',fn()=>same('SC-0001',(string)new ScannerCode('SC-0001')));test('ESC rechazado',fn()=>throws(fn()=>new ScannerCode('ESC-0001')));test('código corto rechazado',fn()=>throws(fn()=>new ScannerCode('SC-001')));test('batería límites',fn()=>same(100,(new BatteryPercentage(100))->value));test('batería inválida',fn()=>throws(fn()=>new BatteryPercentage(101)));test('conservación límites',fn()=>same(0,(new ConservationIndex(0))->value));test('estados',fn()=>same('disponible',(string)new ScannerStatus('disponible')));test('estado inválido',fn()=>throws(fn()=>new MovementStatus('x')));test('inspección',fn()=>same('recepcion',(string)new InspectionType('recepcion')));test('severidad',fn()=>same('critica',(string)new IncidentSeverity('critica')));test('incidencia',fn()=>same('abierta',(string)new IncidentStatus('abierta')));test('folio',fn()=>same('MOV-20260718-ABC123',(string)new ScannerFolio('MOV-20260718-ABC123')));test('orden allowlist',fn()=>throws(fn()=>new ScannerFilterData(orderBy:'DROP TABLE')));test('paginación',fn()=>same(25,(new ScannerFilterData(page:2,perPage:25))->offset()));test('sanitizer recursivo',function(){same(['safe'=>1,'nested'=>['ok'=>2]],AuditPayloadSanitizer::sanitize(['password'=>'x','safe'=>1,'nested'=>['token'=>'x','ok'=>2]]));});finish('Unit Control de Escáneres');
